1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type QuoteStep = { type: "quote"; items: Item[] };
13	type Scenario = { steps: QuoteStep[] };
14	
15	export function runScenario(scenario: unknown): { results: unknown[] } {
16	  const { steps } = scenario as Scenario;
17	  const items = steps[0].items;
18	  const base = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
19	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
20	  const premium = base + firstInsuranceSurcharge + PROCESSING_FEE;
21	  return { results: [{ premium }] };
22	}
